if(!email){statusEl.innerHTML='';this.emailValid=null;return}
var emailRegex=/^[^\s@]+@[^\s@]+\.[^\s@]+$/;if(!emailRegex.test(email)){statusEl.innerHTML='<span class="gpl-email-invalid">❌ Invalid email format</span>';this.emailValid=!1;return}
var disposableDomains=['tempmail.com','throwaway.email','guerrillamail.com','mailinator.com','10minutemail.com','yopmail.com'];var domain=email.split('@')[1].toLowerCase();if(disposableDomains.indexOf(domain)!==-1){statusEl.innerHTML='<span class="gpl-email-invalid">❌ Disposable emails not allowed</span>';this.emailValid=!1;return}
